    "durationSec": 6.4,
    "durationFrames": 192,
    "speaker": "ずんだもん",
    "text": "それまで主流だったMPEG-2と比べて、同じ画質をほぼ半分のデータ量で実現したのだ",
    "speakerColor": "#22c55e",
    "sceneId": 14,
    "sceneTitle": "H.264の登場",
