    "startTimeSec": 815.9520000000003,
    "startFrame": 24479,
    "durationSec": 3.872,
    "durationFrames": 116,
    "speaker": "ずんだもん",
    "text": "じゃあ実際にどう選べばいいか、簡単にまとめるのだ",
