    "startTimeSec": 835.050666666667,
    "startFrame": 25052,
    "durationSec": 5.237333333333333,
    "durationFrames": 157,
    "speaker": "ずんだもん",
    "text": "ProResやDNxHRなど、画質重視のコーデックを選ぶのだ",
